import { useState, useEffect } from 'react'
import { List, Tag, Tabs, Empty, Spin, Button, message } from 'antd'
import {
  ThunderboltOutlined,
  FireOutlined,
  GiftOutlined,
  TeamOutlined,
  BulbOutlined,
  ReloadOutlined
} from '@ant-design/icons'
import factsStore, { Fact } from '../db'
import factExtractor from '../services/factExtractor'

const { TabPane } = Tabs

type FactType = 'all' | 'power' | 'item' | 'relation' | 'foreshadow'

const typeLabels: Record<FactType, { label: string; icon: React.ReactNode; color: string }> = {
  all: { label: '全部', icon: <ThunderboltOutlined />, color: 'default' },
  power: { label: '战力', icon: <FireOutlined />, color: 'red' },
  item: { label: '物品', icon: <GiftOutlined />, color: 'gold' },
  relation: { label: '关系', icon: <TeamOutlined />, color: 'blue' },
  foreshadow: { label: '伏笔', icon: <BulbOutlined />, color: 'purple' },
}

const FactsPanel = () => {
  const [activeTab, setActiveTab] = useState<FactType>('all')
  const [facts, setFacts] = useState<Fact[]>([])
  const [loading, setLoading] = useState(false)

  // 加载事实
  const loadFacts = async () => {
    setLoading(true)
    try {
      const filters = activeTab === 'all' ? undefined : { type: activeTab }
      const result = await factsStore.getFacts(filters)
      setFacts(result)
    } catch (error) {
      message.error('加载事实失败')
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  // 提取当前章节事实
  const extractCurrentChapter = async () => {
    // 这里需要获取当前章节内容，暂时先简单实现
    message.info('功能开发中：将自动提取当前章节的事实')
  }

  // 切换标签时重新加载
  useEffect(() => {
    loadFacts()
  }, [activeTab])

  // 格式化事实项
  const renderFactItem = (item: Fact) => {
    const typeInfo = typeLabels[item.type as FactType]

    return (
      <List.Item key={item.id}>
        <List.Item.Meta
          title={
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <Tag color={typeInfo.color}>
                {typeInfo.icon} {typeInfo.label}
              </Tag>
              <span>{item.subject}</span>
              {item.object && <span style={{ color: '#999' }}>→ {item.object}</span>}
            </div>
          }
          description={
            <div>
              <p>{item.content}</p>
              <div style={{ fontSize: 12, color: '#999', marginTop: 5 }}>
                第 {item.chapterStart} 章
                {item.chapterEnd !== item.chapterStart && ` - 第 ${item.chapterEnd} 章`}
              </div>
            </div>
          }
        />
      </List.Item>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: '10px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
          <h3 style={{ margin: 0 }}>事实台账</h3>
          <Button
            type="primary"
            size="small"
            icon={<ReloadOutlined />}
            onClick={extractCurrentChapter}
          >
            提取本章事实
          </Button>
        </div>
        <Tabs
          activeKey={activeTab}
          onChange={(key) => setActiveTab(key as FactType)}
          size="small"
        >
          {Object.entries(typeLabels).map(([key, info]) => (
            <TabPane
              key={key}
              tab={<span>{info.icon} {info.label}</span>}
            />
          ))}
        </Tabs>
      </div>

      <div style={{ flex: 1, overflow: 'auto', padding: '0 16px' }}>
        {loading ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Spin tip="加载中..." />
          </div>
        ) : facts.length === 0 ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Empty
              description="暂无事实记录"
              image={Empty.PRESENTED_IMAGE_SIMPLE}
            />
          </div>
        ) : (
          <List
            dataSource={facts}
            renderItem={renderFactItem}
            size="small"
            style={{ padding: '10px 0' }}
          />
        )}
      </div>
    </div>
  )
}

export default FactsPanel
