/**
 * 角色管理页面
 * 显示角色列表、卡片展示，点击角色进入详情编辑
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Row,
  Col,
  Button,
  Input,
  Empty,
  Spin,
  Tag,
  message,
  Modal,
  Space,
  Dropdown,
} from 'antd'
import {
  PlusOutlined,
  SearchOutlined,
  UserOutlined,
  EditOutlined,
  DeleteOutlined,
  MoreOutlined,
} from '@ant-design/icons'
import type { MenuProps } from 'antd'
import CharacterDetail from './CharacterDetail'

interface Character {
  id: string
  name: string
  filePath: string
  mbti?: string
  appearance?: string
  ability?: string
  goal?: string
  flaw?: string
  background?: string
  notes?: string
  // 从 relationships.yaml 读取的关系
  relationships?: Array<{
    from: string
    to: string
    type: string
    strength: number
    development?: Array<{ chapter: number; event: string; strength: number }>
  }>
}

const CharactersPage: React.FC<{
  projectRoot: string | null
  onCharacterClick?: (characterName: string) => void
}> = ({ projectRoot, onCharacterClick }) => {
  const [characters, setCharacters] = useState<Character[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [selectedCharacter, setSelectedCharacter] = useState<Character | null>(null)
  const [detailVisible, setDetailVisible] = useState(false)

  // 加载角色列表
  const loadCharacters = async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      const charsDir = `${projectRoot}/characters`
      const dirExists = await window.electronAPI.exists(charsDir)
      if (!dirExists) {
        await window.electronAPI.mkdir(charsDir)
        setCharacters([])
        return
      }

      const entries = await window.electronAPI.readdir(charsDir)
      const charFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      const loadedCharacters: Character[] = []
      for (const file of charFiles) {
        const filePath = `${charsDir}/${file.name}`
        const result = await window.electronAPI.yaml.read(filePath)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          loadedCharacters.push({
            id: file.name.replace('.yaml', ''),
            name: String(data.name || file.name.replace('.yaml', '')),
            filePath,
            mbti: data.mbti as string | undefined,
            appearance: (data.key_attributes as Record<string, string>)?.appearance,
            ability: (data.key_attributes as Record<string, string>)?.ability,
            goal: (data.key_attributes as Record<string, string>)?.goal,
            flaw: (data.key_attributes as Record<string, string>)?.flaw,
            background: data.background as string | undefined,
            notes: data.notes as string | undefined,
          })
        }
      }

      // 加载人物关系
      const relFile = `${projectRoot}/relationships.yaml`
      const relResult = await window.electronAPI.yaml.read(relFile)
      if (relResult.success && relResult.data) {
        const relData = relResult.data as Record<string, unknown>
        const rels = (relData.relationships as Character['relationships']) || []
        for (const char of loadedCharacters) {
          char.relationships = rels.filter(
            r => r.from === char.name || r.to === char.name
          )
        }
      }

      setCharacters(loadedCharacters)
    } catch (error) {
      console.error('加载角色失败:', error)
      message.error('加载角色列表失败')
    } finally {
      setLoading(false)
    }
  }

  // 新建角色
  const handleNewCharacter = () => {
    setSelectedCharacter(null)
    setDetailVisible(true)
  }

  // 编辑角色
  const handleEditCharacter = (char: Character) => {
    setSelectedCharacter(char)
    setDetailVisible(true)
  }

  // 删除角色
  const handleDeleteCharacter = async (char: Character) => {
    Modal.confirm({
      title: `确认删除角色「${char.name}」？`,
      content: '删除后可通过备份恢复，但数据将丢失。',
      okText: '确认删除',
      okType: 'danger',
      cancelText: '取消',
      onOk: async () => {
        try {
          const result = await window.electronAPI.deleteFile(char.filePath)
          if (result.success) {
            message.success(`已删除角色「${char.name}」`)
            loadCharacters()
          } else {
            message.error(`删除失败: ${result.error}`)
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // 保存角色后刷新
  const handleCharacterSaved = () => {
    setDetailVisible(false)
    loadCharacters()
  }

  useEffect(() => {
    loadCharacters()
  }, [projectRoot])

  // 过滤
  const filteredCharacters = characters.filter(char =>
    char.name.toLowerCase().includes(searchText.toLowerCase())
  )

  // 关系类型颜色
  const relTypeColor: Record<string, string> = {
    mentor: 'blue',
    rival: 'red',
    love: 'pink',
    family: 'green',
    friend: 'cyan',
  }

  const getRelationshipTags = (char: Character) => {
    if (!char.relationships || char.relationships.length === 0) return null
    return char.relationships.slice(0, 3).map((rel, idx) => {
      const other = rel.from === char.name ? rel.to : rel.from
      return (
        <Tag key={idx} color={relTypeColor[rel.type] || 'default'}>
          {other} ({rel.type})
        </Tag>
      )
    })
  }

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Empty description="请先打开一个小说项目" />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具栏 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
          <h3 style={{ margin: 0 }}>角色列表</h3>
          <Button
            type="primary"
            icon={<PlusOutlined />}
            onClick={handleNewCharacter}
          >
            新建角色
          </Button>
        </div>
        <Input
          placeholder="搜索角色..."
          prefix={<SearchOutlined />}
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
          allowClear
        />
      </div>

      {/* 角色卡片列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="加载中..." />
          </div>
        ) : filteredCharacters.length === 0 ? (
          <Empty
            description={searchText ? '未找到匹配的角色' : '暂无角色，点击"新建角色"开始创建'}
            image={Empty.PRESENTED_IMAGE_SIMPLE}
          />
        ) : (
          <Row gutter={[16, 16]}>
            {filteredCharacters.map((char) => (
              <Col key={char.id} xs={24} sm={12} md={8} lg={6}>
                <Card
                  hoverable
                  size="small"
                  cover={
                    <div
                      style={{
                        height: 80,
                        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: '#fff',
                        fontSize: 32,
                      }}
                    >
                      <UserOutlined />
                    </div>
                  }
                  actions={[
                    <EditOutlined key="edit" onClick={() => handleEditCharacter(char)} />,
                    <DeleteOutlined
                      key="delete"
                      onClick={() => handleDeleteCharacter(char)}
                      style={{ color: '#ff4d4f' }}
                    />,
                  ]}
                  onClick={() => {
                    if (onCharacterClick) {
                      onCharacterClick(char.name)
                    }
                  }}
                >
                  <Card.Meta
                    title={
                      <div>
                        {char.name}
                        {char.mbti && (
                          <Tag color="purple" style={{ marginLeft: 8, float: 'right' }}>
                            {char.mbti}
                          </Tag>
                        )}
                      </div>
                    }
                    description={
                      <div>
                        {char.ability && (
                          <div
                            style={{
                              overflow: 'hidden',
                              textOverflow: 'ellipsis',
                              whiteSpace: 'nowrap',
                              color: '#666',
                              fontSize: 12,
                            }}
                            title={char.ability}
                          >
                            {char.ability}
                          </div>
                        )}
                        {getRelationshipTags(char)}
                      </div>
                    }
                  />
                </Card>
              </Col>
            ))}
          </Row>
        )}
      </div>

      {/* 角色详情 Modal */}
      <CharacterDetail
        visible={detailVisible}
        character={selectedCharacter}
        projectRoot={projectRoot}
        onClose={() => setDetailVisible(false)}
        onSaved={handleCharacterSaved}
      />
    </div>
  )
}

export default CharactersPage

/**
 * 角色详情编辑页面
 * 支持新建和编辑角色，保存为 YAML 文件
 */

import { useState, useEffect } from 'react'
import {
  Modal,
  Form,
  Input,
  Select,
  Button,
  Space,
  Card,
  Divider,
  message,
  Row,
  Col,
  Switch,
  Tooltip,
} from 'antd'
import {
  SaveOutlined,
  PlusOutlined,
  DeleteOutlined,
  ThunderboltOutlined,
} from '@ant-design/icons'

const { TextArea } = Input

interface RelationshipItem {
  key: string
  target: string
  type: string
  strength: number
}

interface CharacterDetailProps {
  visible: boolean
  character: {
    id: string
    name: string
    filePath: string
    mbti?: string
    appearance?: string
    ability?: string
    goal?: string
    flaw?: string
    background?: string
    notes?: string
  } | null
  projectRoot: string | null
  onClose: () => void
  onSaved: () => void
}

const MBTI_OPTIONS = [
  'INTJ', 'INTP', 'ENTJ', 'ENTP',
  'INFJ', 'INFP', 'ENFJ', 'ENFP',
  'ISTJ', 'ISFJ', 'ESTJ', 'ESFJ',
  'ISTP', 'ISFP', 'ESTP', 'ESFP',
]

const RELATION_TYPES = [
  { value: 'mentor', label: '师徒' },
  { value: 'rival', label: '对手/敌对' },
  { value: 'love', label: '爱恋' },
  { value: 'family', label: '家族' },
  { value: 'friend', label: '朋友/盟友' },
  { value: 'master', label: '师承' },
  { value: 'enemy', label: '仇敌' },
]

const CharacterDetail: React.FC<CharacterDetailProps> = ({
  visible,
  character,
  projectRoot,
  onClose,
  onSaved,
}) => {
  const [form] = Form.useForm()
  const [saving, setSaving] = useState(false)
  const [relationships, setRelationships] = useState<RelationshipItem[]>([])

  // 填充表单
  useEffect(() => {
    if (visible && character) {
      form.setFieldsValue({
        name: character.name,
        mbti: character.mbti,
        appearance: character.appearance,
        ability: character.ability,
        goal: character.goal,
        flaw: character.flaw,
        background: character.background,
        notes: character.notes,
      })
    } else if (visible) {
      form.resetFields()
    }
  }, [visible, character, form])

  // 加载关系数据
  useEffect(() => {
    if (visible && character && projectRoot) {
      loadRelationships()
    }
  }, [visible, character, projectRoot])

  const loadRelationships = async () => {
    if (!projectRoot) return
    try {
      const relFile = `${projectRoot}/relationships.yaml`
      const result = await window.electronAPI.yaml.read(relFile)
      if (result.success && result.data) {
        const relData = result.data as { relationships?: Array<{ from: string; to: string; type: string; strength: number }> }
        const rels = (relData.relationships || []).filter(
          r => r.from === character?.name || r.to === character?.name
        )
        setRelationships(
          rels.map((r, idx) => ({
            key: `${idx}`,
            target: r.from === character?.name ? r.to : r.from,
            type: r.type,
            strength: r.strength,
          }))
        )
      }
    } catch (error) {
      console.error('加载关系失败:', error)
    }
  }

  // 添加关系
  const handleAddRelationship = () => {
    setRelationships(prev => [
      ...prev,
      { key: Date.now().toString(), target: '', type: 'friend', strength: 0.5 },
    ])
  }

  // 删除关系
  const handleRemoveRelationship = (key: string) => {
    setRelationships(prev => prev.filter(r => r.key !== key))
  }

  // 保存角色
  const handleSave = async () => {
    try {
      const values = await form.validateFields()

      if (!values.name) {
        message.error('请输入角色名称')
        return
      }

      if (!projectRoot) {
        message.error('未设置项目根路径')
        return
      }

      setSaving(true)

      // 构建角色数据
      const charData: Record<string, unknown> = {
        name: values.name,
        mbti: values.mbti,
        key_attributes: {
          appearance: values.appearance,
          ability: values.ability,
          goal: values.goal,
          flaw: values.flaw,
        },
        background: values.background,
        notes: values.notes,
      }

      // 确定文件路径
      const safeName = values.name.replace(/[/\\?%*:|"<>]/g, '_')
      const filePath = `${projectRoot}/characters/${safeName}.yaml`

      const result = await window.electronAPI.yaml.write(filePath, charData)
      if (!result.success) {
        message.error(`保存失败: ${result.error}`)
        return
      }

      // 更新关系文件
      if (character?.name && character.name !== values.name) {
        // 角色改名，更新关系文件
        const relFile = `${projectRoot}/relationships.yaml`
        const relResult = await window.electronAPI.yaml.read(relFile)
        if (relResult.success && relResult.data) {
          const relData = relResult.data as {
            relationships?: Array<{
              from: string; to: string; type: string; strength: number; development?: unknown[]
            }>
          }
          const rels = relData.relationships || []
          const updatedRels = rels.map(r => {
            if (r.from === character.name) return { ...r, from: values.name }
            if (r.to === character.name) return { ...r, to: values.name }
            return r
          })
          await window.electronAPI.yaml.write(relFile, { relationships: updatedRels })
        }
      }

      // 保存关系
      if (values.name) {
        const relFile = `${projectRoot}/relationships.yaml`
        const relResult = await window.electronAPI.yaml.read(relFile)
        let relData = (relResult.success && relResult.data) as {
          relationships?: Array<{
            from: string; to: string; type: string; strength: number; development?: unknown[]
          }>
        } || { relationships: [] }

        // 移除旧关系（如果编辑的是已有角色）
        if (character?.name) {
          relData.relationships = (relData.relationships || []).filter(
            r => r.from !== values.name && r.to !== values.name
          )
        }

        // 添加新关系
        const newRels = relationships
          .filter(r => r.target && r.type)
          .map(r => ({
            from: character?.name && !relationships.find(
              (nr) => nr.key === r.key && nr.target === character.name
            ) ? character.name : values.name,
            to: r.target,
            type: r.type,
            strength: r.strength,
            development: character?.name ? undefined : [
              { chapter: 1, event: '初遇', strength: r.strength },
            ],
          }))

        // 如果是新建角色，当前角色作为 from
        const finalRels = newRels.map(r => ({
          from: character?.name || values.name,
          to: r.to,
          type: r.type,
          strength: r.strength,
          development: [{ chapter: 1, event: '初遇', strength: r.strength }],
        }))

        relData.relationships = [...(relData.relationships || []), ...finalRels]
        await window.electronAPI.yaml.write(relFile, relData)
      }

      message.success('角色已保存')
      onSaved()
    } catch (error) {
      console.error('保存角色失败:', error)
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  return (
    <Modal
      title={character ? `编辑角色：${character.name}` : '新建角色'}
      open={visible}
      onCancel={onClose}
      width={800}
      footer={
        <Space>
          <Button onClick={onClose}>取消</Button>
          <Button
            type="primary"
            icon={<SaveOutlined />}
            loading={saving}
            onClick={handleSave}
          >
            保存
          </Button>
        </Space>
      }
    >
      <Form
        form={form}
        layout="vertical"
        style={{ maxHeight: '70vh', overflow: 'auto' }}
      >
        <Row gutter={16}>
          <Col span={12}>
            <Form.Item
              name="name"
              label="角色名称"
              rules={[{ required: true, message: '请输入角色名称' }]}
            >
              <Input placeholder="如：林枫" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item name="mbti" label="MBTI">
              <Select
                placeholder="选择人格类型"
                options={MBTI_OPTIONS.map(m => ({ value: m, label: m }))}
                allowClear
              />
            </Form.Item>
          </Col>
        </Row>

        <Divider orientation="left">
          <ThunderboltOutlined /> 核心属性
        </Divider>

        <Form.Item name="ability" label="能力/特长">
          <Input placeholder="如：剑术天才，重生后拥有前世记忆" />
        </Form.Item>

        <Form.Item name="goal" label="核心目标">
          <Input placeholder="如：推翻血魔宗，拯救修真界" />
        </Form.Item>

        <Form.Item name="flaw" label="核心缺陷/弱点">
          <Input placeholder="如：过于理性，不善表达情感" />
        </Form.Item>

        <Form.Item name="appearance" label="外貌特征">
          <TextArea
            placeholder="如：黑色长发，冷峻面容，眼神锐利"
            rows={2}
          />
        </Form.Item>

        <Divider orientation="left">背景故事</Divider>

        <Form.Item name="background" label="背景">
          <TextArea
            placeholder="角色背景故事..."
            rows={4}
          />
        </Form.Item>

        <Form.Item name="notes" label="创作笔记">
          <TextArea
            placeholder="如：后期需要设计一个情感突破口..."
            rows={3}
          />
        </Form.Item>

        <Divider orientation="left">人物关系</Divider>

        <div style={{ marginBottom: 12 }}>
          <Button
            type="dashed"
            icon={<PlusOutlined />}
            onClick={handleAddRelationship}
            block
          >
            添加关系
          </Button>
        </div>

        {relationships.map((rel, idx) => (
          <Card
            key={rel.key}
            size="small"
            style={{ marginBottom: 8 }}
          >
            <Row gutter={12} align="middle">
              <Col span={8}>
                <Input
                  placeholder="对方角色名"
                  value={rel.target}
                  onChange={(e) => {
                    const updated = [...relationships]
                    updated[idx].target = e.target.value
                    setRelationships(updated)
                  }}
                />
              </Col>
              <Col span={6}>
                <Select
                  value={rel.type}
                  onChange={(val) => {
                    const updated = [...relationships]
                    updated[idx].type = val
                    setRelationships(updated)
                  }}
                  options={RELATION_TYPES}
                  style={{ width: '100%' }}
                />
              </Col>
              <Col span={6}>
                <Input
                  type="number"
                  min={0}
                  max={1}
                  step={0.1}
                  placeholder="强度 0-1"
                  value={rel.strength}
                  onChange={(e) => {
                    const updated = [...relationships]
                    updated[idx].strength = parseFloat(e.target.value) || 0
                    setRelationships(updated)
                  }}
                />
              </Col>
              <Col span={4}>
                <Button
                  type="text"
                  danger
                  icon={<DeleteOutlined />}
                  onClick={() => handleRemoveRelationship(rel.key)}
                />
              </Col>
            </Row>
          </Card>
        ))}

        {relationships.length === 0 && (
          <div style={{ color: '#999', textAlign: 'center', padding: 16 }}>
            暂无关系，点击上方按钮添加
          </div>
        )}
      </Form>
    </Modal>
  )
}

export default CharacterDetail

/**
 * 世界设定页面
 * 显示世界观设定列表，支持新建、编辑、删除设定
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Row,
  Col,
  Button,
  Input,
  Empty,
  Spin,
  Tag,
  message,
  Modal,
  List,
  Space,
  Dropdown,
} from 'antd'
import {
  PlusOutlined,
  SearchOutlined,
  EditOutlined,
  DeleteOutlined,
  SettingOutlined,
  CheckCircleOutlined,
} from '@ant-design/icons'
import type { MenuProps } from 'antd'
import SettingDetail from './SettingDetail'
import aiModelService from '../services/aiModels'

interface WorldSetting {
  id: string
  name: string
  filePath: string
  summary?: string
  category?: string
}

interface SettingsPageProps {
  projectRoot: string | null
}

const SettingsPage: React.FC<SettingsPageProps> = ({ projectRoot }) => {
  const [settings, setSettings] = useState<WorldSetting[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [selectedSetting, setSelectedSetting] = useState<WorldSetting | null>(null)
  const [detailVisible, setDetailVisible] = useState(false)
  const [checkingConsistency, setCheckingConsistency] = useState(false)

  // 加载设定列表
  const loadSettings = async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      const settingsDir = `${projectRoot}/settings`
      const dirExists = await window.electronAPI.exists(settingsDir)
      if (!dirExists) {
        await window.electronAPI.mkdir(settingsDir)
        setSettings([])
        return
      }

      const entries = await window.electronAPI.readdir(settingsDir)
      const settingFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      const loadedSettings: WorldSetting[] = []
      for (const file of settingFiles) {
        const filePath = `${settingsDir}/${file.name}`
        const result = await window.electronAPI.yaml.read(filePath)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          // 提取第一行作为摘要（去掉 # 注释）
          const rawContent = typeof data._raw === 'string'
            ? data._raw
            : ''
          loadedSettings.push({
            id: file.name.replace('.yaml', ''),
            name: String(data.name || file.name.replace('.yaml', '')),
            filePath,
            summary: typeof data.summary === 'string' ? data.summary : rawContent.slice(0, 100),
            category: data.category as string | undefined,
          })
        }
      }

      setSettings(loadedSettings)
    } catch (error) {
      console.error('加载设定失败:', error)
      message.error('加载设定列表失败')
    } finally {
      setLoading(false)
    }
  }

  // 新建设定
  const handleNewSetting = () => {
    setSelectedSetting(null)
    setDetailVisible(true)
  }

  // 编辑设定
  const handleEditSetting = (setting: WorldSetting) => {
    setSelectedSetting(setting)
    setDetailVisible(true)
  }

  // 删除设定
  const handleDeleteSetting = async (setting: WorldSetting) => {
    Modal.confirm({
      title: `确认删除设定「${setting.name}」？`,
      content: '删除后可通过备份恢复。',
      okText: '确认删除',
      okType: 'danger',
      cancelText: '取消',
      onOk: async () => {
        try {
          const result = await window.electronAPI.deleteFile(setting.filePath)
          if (result.success) {
            message.success(`已删除设定「${setting.name}」`)
            loadSettings()
          } else {
            message.error(`删除失败: ${result.error}`)
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // AI 一致性检查
  const handleConsistencyCheck = async () => {
    if (!projectRoot) return
    setCheckingConsistency(true)
    try {
      // 收集所有设定文件内容
      const settingsDir = `${projectRoot}/settings`
      const entries = await window.electronAPI.readdir(settingsDir)
      const settingFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      let allSettingsContent = ''
      for (const file of settingFiles) {
        const result = await window.electronAPI.yaml.read(`${settingsDir}/${file.name}`)
        if (result.success && result.data) {
          allSettingsContent += `\n### ${file.name.replace('.yaml', '')} ###\n`
          allSettingsContent += JSON.stringify(result.data, null, 2)
        }
      }

      if (!allSettingsContent.trim()) {
        message.warning('暂无设定可检查')
        return
      }

      const checkPrompt = `请检查以下世界设定内容，找出其中的矛盾点和不一致之处：

${allSettingsContent}

检查维度：
1. 战力体系是否矛盾（等级划分是否自洽）
2. 地理/空间设定是否冲突
3. 势力/门派设定是否矛盾
4. 时间线是否自洽
5. 能力设定是否有冲突

请列出发现的所有矛盾点，并给出修改建议。如果一切自洽，也请明确说明。`

      const result = await aiModelService.call(
        'logic',
        checkPrompt,
        {
          systemPrompt: '你是一个严格的世界观设定审核专家。请仔细检查设定的逻辑一致性。',
        }
      )

      if (result.success && result.content) {
        Modal.info({
          title: '🏛️ 世界观一致性检查结果',
          content: (
            <pre style={{
              maxHeight: 400,
              overflow: 'auto',
              whiteSpace: 'pre-wrap',
              fontSize: 13,
              fontFamily: 'monospace',
            }}>
              {result.content}
            </pre>
          ),
          width: 700,
          okText: '关闭',
        })
      } else {
        message.error(result.error || '检查失败')
      }
    } catch (error) {
      message.error('一致性检查失败')
    } finally {
      setCheckingConsistency(false)
    }
  }

  // 保存后刷新
  const handleSettingSaved = () => {
    setDetailVisible(false)
    loadSettings()
  }

  useEffect(() => {
    loadSettings()
  }, [projectRoot])

  // 过滤
  const filteredSettings = settings.filter(s =>
    s.name.toLowerCase().includes(searchText.toLowerCase())
  )

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Empty description="请先打开一个小说项目" />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具栏 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            marginBottom: 10,
          }}
        >
          <h3 style={{ margin: 0 }}>世界观设定</h3>
          <Space>
            <Button
              icon={<CheckCircleOutlined />}
              onClick={handleConsistencyCheck}
              loading={checkingConsistency}
            >
              AI一致性检查
            </Button>
            <Button
              type="primary"
              icon={<PlusOutlined />}
              onClick={handleNewSetting}
            >
              新建设定
            </Button>
          </Space>
        </div>
        <Input
          placeholder="搜索设定..."
          prefix={<SearchOutlined />}
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
          allowClear
        />
      </div>

      {/* 设定列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="加载中..." />
          </div>
        ) : filteredSettings.length === 0 ? (
          <Empty
            description={
              searchText
                ? '未找到匹配的设定'
                : '暂无设定，点击"新建设定"开始创建'
            }
            image={Empty.PRESENTED_IMAGE_SIMPLE}
          />
        ) : (
          <List
            grid={{ gutter: 16, xs: 1, sm: 2, md: 3 }}
            dataSource={filteredSettings}
            renderItem={(item) => (
              <List.Item>
                <Card
                  hoverable
                  size="small"
                  actions={[
                    <EditOutlined
                      key="edit"
                      onClick={() => handleEditSetting(item)}
                    />,
                    <DeleteOutlined
                      key="delete"
                      onClick={() => handleDeleteSetting(item)}
                      style={{ color: '#ff4d4f' }}
                    />,
                  ]}
                >
                  <Card.Meta
                    avatar={<SettingOutlined style={{ fontSize: 24, color: '#1890ff' }} />}
                    title={
                      <div>
                        {item.name}
                        {item.category && (
                          <Tag color="blue" style={{ marginLeft: 8, float: 'right' }}>
                            {item.category}
                          </Tag>
                        )}
                      </div>
                    }
                    description={
                      item.summary && (
                        <div
                          style={{
                            fontSize: 12,
                            color: '#666',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            display: '-webkit-box',
                            WebkitLineClamp: 3,
                            WebkitBoxOrient: 'vertical',
                          }}
                        >
                          {item.summary}
                        </div>
                      )
                    }
                  />
                </Card>
              </List.Item>
            )}
          />
        )}
      </div>

      {/* 设定详情 Modal */}
      <SettingDetail
        visible={detailVisible}
        setting={selectedSetting}
        projectRoot={projectRoot}
        onClose={() => setDetailVisible(false)}
        onSaved={handleSettingSaved}
      />
    </div>
  )
}

export default SettingsPage

/**
 * 设定详情编辑页面
 * 支持新建和编辑世界观设定，保存为 YAML 文件
 */

import { useState, useEffect } from 'react'
import {
  Modal,
  Form,
  Input,
  Select,
  Button,
  Space,
  Divider,
  message,
  Tabs,
} from 'antd'
import { SaveOutlined } from '@ant-design/icons'

const { TextArea } = Input

interface SettingDetailProps {
  visible: boolean
  setting: {
    id: string
    name: string
    filePath: string
    summary?: string
    category?: string
  } | null
  projectRoot: string | null
  onClose: () => void
  onSaved: () => void
}

const CATEGORIES = [
  { value: 'magic', label: '魔法/功法体系' },
  { value: 'geography', label: '地理/世界设定' },
  { value: 'faction', label: '势力/门派' },
  { value: 'timeline', label: '时间线/历史' },
  { value: 'culture', label: '文化/社会' },
  { value: 'technology', label: '科技/道具' },
  { value: 'other', label: '其他' },
]

const SettingDetail: React.FC<SettingDetailProps> = ({
  visible,
  setting,
  projectRoot,
  onClose,
  onSaved,
}) => {
  const [form] = Form.useForm()
  const [saving, setSaving] = useState(false)
  const [rawContent, setRawContent] = useState('')

  // 填充表单
  useEffect(() => {
    if (visible && setting) {
      form.setFieldsValue({
        name: setting.name,
        category: setting.category,
        summary: setting.summary,
      })
    } else if (visible) {
      form.resetFields()
    }
  }, [visible, setting, form])

  // 加载原始内容用于编辑
  useEffect(() => {
    if (visible && setting) {
      loadRawContent()
    }
  }, [visible, setting])

  const loadRawContent = async () => {
    if (!setting) return
    try {
      const result = await window.electronAPI.readFile(setting.filePath)
      if (result.success && result.content) {
        setRawContent(result.content)
      }
    } catch (error) {
      console.error('加载设定内容失败:', error)
    }
  }

  // 保存设定
  const handleSave = async () => {
    try {
      const values = await form.validateFields()

      if (!values.name) {
        message.error('请输入设定名称')
        return
      }

      if (!projectRoot) {
        message.error('未设置项目根路径')
        return
      }

      setSaving(true)

      // 如果有原始内容（YAML格式良好），尝试解析并更新
      // 否则用表单数据构建
      let finalData: Record<string, unknown>

      if (setting && rawContent) {
        // 尝试解析现有YAML，保留格式
        try {
          const parsed = await window.electronAPI.yaml.read(setting.filePath)
          if (parsed.success && parsed.data) {
            finalData = parsed.data as Record<string, unknown>
            finalData.name = values.name
            finalData.category = values.category
            finalData.summary = values.summary
          } else {
            finalData = buildData(values)
          }
        } catch {
          finalData = buildData(values)
        }
      } else {
        finalData = buildData(values)
      }

      const safeName = values.name.replace(/[/\\?%*:|"<>]/g, '_')
      const filePath = `${projectRoot}/settings/${safeName}.yaml`

      const result = await window.electronAPI.yaml.write(filePath, finalData)
      if (!result.success) {
        message.error(`保存失败: ${result.error}`)
        return
      }

      message.success('设定已保存')
      onSaved()
    } catch (error) {
      console.error('保存设定失败:', error)
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  const buildData = (values: Record<string, unknown>) => {
    return {
      name: values.name,
      category: values.category,
      summary: values.summary || '',
      created_at: setting ? undefined : new Date().toISOString().split('T')[0],
      updated_at: new Date().toISOString().split('T')[0],
    }
  }

  return (
    <Modal
      title={setting ? `编辑设定：${setting.name}` : '新建设定'}
      open={visible}
      onCancel={onClose}
      width={700}
      footer={
        <Space>
          <Button onClick={onClose}>取消</Button>
          <Button
            type="primary"
            icon={<SaveOutlined />}
            loading={saving}
            onClick={handleSave}
          >
            保存
          </Button>
        </Space>
      }
    >
      <Form
        form={form}
        layout="vertical"
        style={{ maxHeight: '70vh', overflow: 'auto' }}
      >
        <Form.Item
          name="name"
          label="设定名称"
          rules={[{ required: true, message: '请输入设定名称' }]}
        >
          <Input placeholder="如：魔法体系、地理设定、修真等级" />
        </Form.Item>

        <Form.Item name="category" label="分类">
          <Select
            placeholder="选择设定分类"
            options={CATEGORIES}
            allowClear
          />
        </Form.Item>

        <Form.Item name="summary" label="简介">
          <TextArea
            placeholder="简要描述此设定..."
            rows={3}
          />
        </Form.Item>

        <Divider orientation="left">设定详情内容</Divider>

        <Form.Item
          extra={
            <span style={{ color: '#999', fontSize: 12 }}>
              可以直接粘贴已有的 Markdown/YAML 格式设定内容，将被正确解析
            </span>
          }
        >
          <TextArea
            placeholder="在此输入设定详细内容...
也可以直接粘贴已有的 Markdown 格式内容，例如：

## 魔法分类
### 元素魔法
- 火系: 攻击力强，消耗大
- 水系: 治疗和控制

## 魔法等级
### 学徒级
- 能使用基础元素魔法..."
            rows={15}
            value={rawContent}
            onChange={(e) => setRawContent(e.target.value)}
            style={{ fontFamily: 'monospace', fontSize: 13 }}
          />
        </Form.Item>
      </Form>
    </Modal>
  )
}

export default SettingDetail

