/**
 * AI 工具面板
 * 包含：智能续写、定向扩写、逻辑校验、提取事实、AI重写、AI润色、大纲生成、风格迁移
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Card,
  Input,
  message,
  Spin,
  Modal,
  Select,
  Divider,
  Tooltip,
  Tabs,
  Alert,
} from 'antd'
import {
  EditOutlined,
  ExpandOutlined,
  CheckCircleOutlined,
  ThunderboltOutlined,
  SaveOutlined,
  SyncOutlined,
  BulbOutlined,
  BgColorsOutlined,
  ProfileOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'
import factExtractor, { ExtractedFact } from '../services/factExtractor'

const { TextArea } = Input

interface AIToolsPanelProps {
  chapterContent: string
  chapterPath: string | null
  onInsertText: (text: string) => void
}

const STYLE_OPTIONS = [
  { value: '金庸', label: '金庸（武侠古典）' },
  { value: '猫腻', label: '猫腻（文笔华丽）' },
  { value: '烽火戏诸侯', label: '烽火戏诸侯（热血燃系）' },
  { value: '乌山居', label: '乌山居（简洁流畅）' },
  { value: '辰东', label: '辰东（宏大壮阔）' },
  { value: '土豆', label: '土豆（小白文爽文）' },
]

const AIToolsPanel = ({ chapterContent, chapterPath, onInsertText }: AIToolsPanelProps) => {
  const [generating, setGenerating] = useState(false)
  const [result, setResult] = useState('')
  const [prompt, setPrompt] = useState('')
  const [extractedFacts, setExtractedFacts] = useState<ExtractedFact[]>([])
  const [activeTool, setActiveTool] = useState<string>('continue')

  // 智能续写
  const handleContinue = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节并编写内容')
      return
    }
    setActiveTool('continue')
    setGenerating(true)
    setResult('')

    try {
      const context = chapterContent.slice(-800)
      const fullPrompt = `请继续写下面的小说内容，风格保持一致，衔接自然：

${context}

续写内容（请直接输出续写文本，不需要加标题）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => message.error(`续写失败：${error}`)
      )
    } catch (error) {
      message.error('续写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 定向扩写
  const handleExpand = async () => {
    if (!prompt) {
      message.warning('请输入扩写要求')
      return
    }
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('expand')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请根据以下要求扩写小说内容。要求：${prompt}

当前章节上下文：
${chapterContent.slice(-1200)}

扩写后的内容（请直接输出扩写文本）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => message.error(`扩写失败：${error}`)
      )
    } catch (error) {
      message.error('扩写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 逻辑校验
  const handleCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('check')
    setGenerating(true)
    setResult('')

    try {
      const checkResult = await aiModelService.call(
        'logic',
        chapterContent,
        {
          systemPrompt: `请检查以下小说章节内容的逻辑一致性，找出矛盾点、战力崩坏、情节不合理的地方，给出修改建议。请使用清晰的格式输出检查结果。`
        }
      )

      if (checkResult.success && checkResult.content) {
        setResult(checkResult.content)
      } else {
        message.error(checkResult.error || '校验失败')
      }
    } catch (error) {
      message.error('逻辑校验失败')
    } finally {
      setGenerating(false)
    }
  }

  // 提取事实
  const handleExtract = async () => {
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('extract')
    setGenerating(true)
    setResult('')

    try {
      const chapterMatch = chapterPath.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1

      const facts = await factExtractor.extract(chapterContent, chapterNumber)
      setExtractedFacts(facts)

      if (facts.length === 0) {
        setResult('未提取到任何事实')
        return
      }

      let output = `提取到 ${facts.length} 条事实：\n\n`
      facts.forEach((fact, index) => {
        output += `${index + 1}. [${fact.type}] ${fact.subject}${fact.object ? ' → ' + fact.object : ''}\n`
        output += `   ${fact.content} (置信度: ${(fact.confidence * 100).toFixed(0)}%)\n\n`
      })

      output += `\n点击「保存到台账」将以上事实追加写入 facts YAML 文件。`
      setResult(output)
    } catch (error) {
      message.error('事实提取失败')
    } finally {
      setGenerating(false)
    }
  }

  // 保存提取的事实到 facts 台账
  const handleSaveFacts = async () => {
    if (extractedFacts.length === 0) return
    setGenerating(true)
    try {
      const chapterMatch = chapterPath?.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1
      const saved = await factExtractor.extractAndSave(chapterContent, chapterNumber)
      if (saved.length > 0) {
        message.success(`已保存 ${saved.length} 条事实到台账`)
        setResult('')
        setExtractedFacts([])
      } else {
        message.error('保存失败')
      }
    } catch (error) {
      message.error('保存失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 新增功能 ──────────────────────────────────────────────────────────────

  // AI 重写
  const [rewriteMode, setRewriteMode] = useState<'chapter' | 'paragraph'>('chapter')
  const [rewritePrompt, setRewritePrompt] = useState('')

  const handleRewrite = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('rewrite')
    setGenerating(true)
    setResult('')

    try {
      let rewritePromptText = rewritePrompt || '请重新组织语言，保持相同的情节和主题'
      const modeText = rewriteMode === 'chapter' ? '整章' : '所选段落'

      if (rewriteMode === 'paragraph') {
        // 取最后一段（如果用户只选了某段的话，用最后500字作为示例）
        const para = chapterContent.slice(-500)
        const fullPrompt = `请重写以下小说段落，保持情节和主题不变，但改善文笔和叙事：

原文：
${para}

重写要求：${rewritePromptText}

重写后的内容（直接输出）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => message.error(`重写失败：${error}`)
        )
      } else {
        const fullPrompt = `请重写以下小说章节，保持情节和主题不变，但改善文笔和叙事：

原文：
${chapterContent.slice(-2000)}

重写要求：${rewritePromptText}

重写后的内容（直接输出）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => message.error(`重写失败：${error}`)
        )
      }
    } catch (error) {
      message.error('重写失败')
    } finally {
      setGenerating(false)
    }
  }

  // AI 润色
  const handlePolish = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('polish')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请对以下小说内容进行文笔润色，改善表达流畅度、精简冗余、提升文字质感，但不改变原意和情节：

原文：
${chapterContent.slice(-1500)}

润色后的内容（直接输出，不要加说明）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => message.error(`润色失败：${error}`)
      )
    } catch (error) {
      message.error('润色失败')
    } finally {
      setGenerating(false)
    }
  }

  // 大纲生成
  const [outlineMode, setOutlineMode] = useState<'chapter' | 'full'>('chapter')

  const handleGenerateOutline = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('outline')
    setGenerating(true)
    setResult('')

    try {
      if (outlineMode === 'chapter') {
        // 为当前章节生成详细大纲
        const fullPrompt = `请分析以下章节内容，生成该章节的详细写作大纲，包括：
1. 本章核心事件
2. 主要情节点（按顺序列出）
3. 角色出场安排
4. 高潮和转折点
5. 伏笔铺设（如有）

章节内容：
${chapterContent}

章节大纲（格式清晰）：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => message.error(`大纲生成失败：${error}`)
        )
      } else {
        // 整本书大纲生成（需要更多上下文）
        const fullPrompt = `请根据以下已知章节内容，为这本小说生成整体大纲框架（包括：
- 主线剧情概述
- 主要角色弧光
- 关键情节点（起承转合）
- 世界观核心设定
- 伏笔和悬念布局

已有章节内容：
${chapterContent.slice(0, 3000)}

整体大纲框架：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => message.error(`大纲生成失败：${error}`)
        )
      }
    } catch (error) {
      message.error('大纲生成失败')
    } finally {
      setGenerating(false)
    }
  }

  // 风格迁移
  const [selectedStyle, setSelectedStyle] = useState<string>('')

  const handleStyleTransfer = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!selectedStyle) {
      message.warning('请选择目标风格')
      return
    }
    setActiveTool('style')
    setGenerating(true)
    setResult('')

    try {
      const stylePrompt = STYLE_OPTIONS.find(s => s.value === selectedStyle)?.label || selectedStyle
      const fullPrompt = `请用"${stylePrompt}的风格"重写以下小说内容。保持情节不变，但采用该作家特有的叙事风格、文笔特点：

原文：
${chapterContent.slice(-1500)}

风格迁移后的内容（直接输出）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => message.error(`风格迁移失败：${error}`)
      )
    } catch (error) {
      message.error('风格迁移失败')
    } finally {
      setGenerating(false)
    }
  }

  // 应用生成结果（替换/追加到编辑器）
  const handleApply = () => {
    if (!result) return
    Modal.confirm({
      title: '插入方式',
      content: '选择如何将生成内容插入编辑器：',
      okText: '追加到末尾',
      cancelText: '取消',
      onOk: () => {
        onInsertText(result)
        message.success('已追加到编辑器')
        setResult('')
      },
    })
  }

  // 替换全文
  const handleReplace = () => {
    if (!result) return
    Modal.confirm({
      title: '确认替换',
      content: '将使用生成的内容完全替换当前章节内容？',
      okText: '确认替换',
      okType: 'warning',
      cancelText: '取消',
      onOk: () => {
        // 通过 onInsertText 返回空字符串+特殊标记让 Workbench 知道要替换
        onInsertText(`__REPLACE__${result}`)
        message.success('已替换章节内容')
        setResult('')
      },
    })
  }

  // 新增工具 Tab 配置
  const toolTabs = [
    { key: 'writing', label: '✏️ 写作' },
    { key: 'review', label: '🔍 校验' },
    { key: 'outline', label: '📋 大纲' },
  ]

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具标签页 */}
      <div style={{ padding: '10px 16px 0', borderBottom: '1px solid #e8e8e8' }}>
        <Tabs
          activeKey={activeTool}
          onChange={(key) => {
            setActiveTool(key)
            setResult('')
            setExtractedFacts([])
          }}
          size="small"
          items={[
            {
              key: 'writing',
              label: '✏️ 写作',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      type="primary"
                      block
                      icon={<EditOutlined />}
                      onClick={handleContinue}
                      loading={generating && activeTool === 'continue'}
                      disabled={!chapterContent}
                    >
                      智能续写
                    </Button>
                    <Button
                      block
                      icon={<ExpandOutlined />}
                      onClick={handleExpand}
                      loading={generating && activeTool === 'expand'}
                      disabled={!chapterContent}
                    >
                      定向扩写
                    </Button>
                    <Button
                      block
                      icon={<SyncOutlined />}
                      onClick={handleRewrite}
                      loading={generating && activeTool === 'rewrite'}
                      disabled={!chapterContent}
                    >
                      AI重写
                    </Button>
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handlePolish}
                      loading={generating && activeTool === 'polish'}
                      disabled={!chapterContent}
                    >
                      AI润色
                    </Button>

                    <TextArea
                      placeholder="扩写/重写要求（可选）"
                      rows={2}
                      value={prompt}
                      onChange={(e) => setPrompt(e.target.value)}
                    />
                  </Space>

                  {activeTool === 'rewrite' && (
                    <div style={{ marginTop: 8 }}>
                      <Space>
                        <Select
                          value={rewriteMode}
                          onChange={setRewriteMode}
                          options={[
                            { value: 'chapter', label: '整章重写' },
                            { value: 'paragraph', label: '段落重写' },
                          ]}
                          style={{ width: 120 }}
                          size="small"
                        />
                      </Space>
                      <Input
                        placeholder="重写要求（可选，如：更简洁、更紧张）"
                        size="small"
                        value={rewritePrompt}
                        onChange={(e) => setRewritePrompt(e.target.value)}
                        style={{ marginTop: 6, width: '100%' }}
                      />
                    </div>
                  )}

                  {activeTool === 'polish' && (
                    <Alert
                      message="润色将改善文笔表达，精简冗余，但保持原意"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'review',
              label: '🔍 校验',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<CheckCircleOutlined />}
                      onClick={handleCheck}
                      loading={generating && activeTool === 'check'}
                      disabled={!chapterContent}
                    >
                      逻辑校验
                    </Button>
                    <Button
                      block
                      icon={<ThunderboltOutlined />}
                      onClick={handleExtract}
                      loading={generating && activeTool === 'extract'}
                      disabled={!chapterContent}
                    >
                      提取事实
                    </Button>
                  </Space>
                </div>
              ),
            },
            {
              key: 'outline',
              label: '📋 大纲',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<ProfileOutlined />}
                      onClick={() => {
                        setOutlineMode('chapter')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成本章大纲
                    </Button>
                    <Button
                      block
                      icon={<BulbOutlined />}
                      onClick={() => {
                        setOutlineMode('full')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成整体大纲
                    </Button>
                    <Divider style={{ margin: '8px 0' }} />
                    <Select
                      placeholder="选择风格"
                      value={selectedStyle || undefined}
                      onChange={setSelectedStyle}
                      options={STYLE_OPTIONS}
                      style={{ width: '100%' }}
                      allowClear
                    />
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handleStyleTransfer}
                      loading={generating && activeTool === 'style'}
                      disabled={!chapterContent || !selectedStyle}
                    >
                      风格迁移
                    </Button>
                  </Space>
                </div>
              ),
            },
          ]}
        />
      </div>

      {/* 结果显示区 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {generating ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="AI 生成中..." />
          </div>
        ) : result ? (
          <Card
            size="small"
            title="生成结果"
            extra={
              <Space>
                {extractedFacts.length > 0 && (
                  <Button
                    type="primary"
                    size="small"
                    icon={<SaveOutlined />}
                    onClick={handleSaveFacts}
                    loading={generating}
                  >
                    保存到台账
                  </Button>
                )}
                <Button type="link" size="small" onClick={handleApply}>
                  插入
                </Button>
                {(activeTool === 'rewrite' || activeTool === 'polish' || activeTool === 'style') && (
                  <Button type="link" size="small" onClick={handleReplace} danger>
                    替换全文
                  </Button>
                )}
              </Space>
            }
            style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
          >
            {result}
          </Card>
        ) : (
          <div style={{ color: '#999', textAlign: 'center', padding: 40 }}>
            选择上方工具开始使用 AI 辅助创作
          </div>
        )}
      </div>
    </div>
  )
}

export default AIToolsPanel

