                    <Card.Meta
                      avatar={<ProjectOutlined style={{ fontSize: 24, color: '#1890ff' }} />}
                      title={project.name}
                      description={
                        <div style={{ fontSize: 12, color: '#999' }}>
                          <div style={{ marginBottom: 4 }}>
                            <Tag size="small">{GENRE_OPTIONS.find(g => g.value === project.genre)?.label || project.genre}</Tag>
                            <Tag size="small" color={project.status === 'writing' ? 'green' : 'orange'}>
                              {project.status === 'writing' ? '创作中' : '规划中'}
                            </Tag>
                          </div>
                          <div style={{ wordBreak: 'break-all', fontSize: 11 }}>
                            {project.path}
                          </div>
                        </div>
                      }
                    />
                  </Card>
                </List.Item>
              )}
            />
          )}
        </div>
      )}
    </Modal>
  )
