#!/usr/bin/env node

/**
 * 构建向量索引命令行工具
 * 用于为项目文件创建向量索引，支持语义检索
 */

const { Command } = require('commander');
const { VectorIndex } = require('../lib/vectorIndex');

const program = new Command();

program
  .description('构建向量索引')
  .requiredOption('-p, --project <path>', '项目路径（包含 project.yaml 的目录）')
  .option('--rebuild', '强制重建索引（即使已存在）', false)
  .action(async (options) => {
    try {
      const projectPath = options.project;
      const index = new VectorIndex(projectPath);

      // 检查是否已有索引
      if (!options.rebuild) {
        const loaded = await index.load();
        if (loaded) {
          console.log('索引已存在，使用 --rebuild 强制重建');
          console.log(`当前索引包含 ${index.documents.length} 个文档`);
          return;
        }
      }

      console.log('正在构建向量索引...');
      console.log('(首次运行需要下载模型，请耐心等待)');

      const count = await index.build();

      console.log(`\n✅ 索引构建完成！`);
      console.log(`   - 文档数量：${count}`);
      console.log(`   - 索引位置：${index.indexFile}`);

    } catch (error) {
      // MODULE_NOT_FOUND / SHARP_INIT_FAILED 是环境问题，不是用户操作问题
      // 其他错误才显示完整错误堆栈
      if (error.code === 'MODULE_NOT_FOUND' || error.code === 'SHARP_INIT_FAILED') {
        console.error(error.message);
      } else {
        console.error('构建索引时出错:', error.message);
      }
      process.exit(1);
    }

