/**
 * 轻量级向量索引服务
 * 使用 transformers.js 进行本地向量化
 *
 * 依赖：@xenova/transformers（需要 Node.js 环境，非浏览器）
 * 如果依赖不可用，build() 和 search() 会抛出明确错误
 */

const fs = require('fs');
const path = require('path');
const yaml = require('js-yaml');

// ─── 嵌入模型初始化（延迟加载） ─────────────────────────────────────────────

let embedder = null;

async function initEmbedder() {
  if (embedder) return embedder;

  let transformers;
  try {
    transformers = require('@xenova/transformers');
  } catch (e) {
    const err = new Error(
      '向量索引功能不可用：缺少 @xenova/transformers 依赖。\n' +
      '请在 my-novel-tools 目录下运行：npm install @xenova/transformers\n' +
      '（需要 Node.js 18+ 环境）'
    );
    err.code = 'MODULE_NOT_FOUND';
    throw err;
  }

  try {
    embedder = await transformers.pipeline('feature-extraction', 'Xenova/bge-small-zh-v1.5');
    return embedder;
  } catch (e) {
    // sharp 原生二进制问题（WSL/Linux 常见）
    if (e.message.includes('sharp') || e.code === 'MODULE_NOT_FOUND') {
      const err = new Error(
        '向量索引功能不可用：@xenova/transformers 的原生依赖(sharp)初始化失败。\n' +
        '这在 WSL 或部分 Linux 环境中常见，不影响核心创作功能。\n' +
        'build-vector-index 命令暂时不可用。'
      );
      err.code = 'SHARP_INIT_FAILED';
      throw err;
    }
    throw e;
  }
}

/**
 * 生成文本的向量表示
 * @param {string} text - 输入文本
 * @returns {Promise<number[]>} - 向量数组
 */
async function embedText(text) {
  const model = await initEmbedder();
  const output = await model(text, { pooling: 'mean', normalize: true });
  return Array.from(output.data);
}

// ─── 向量索引类 ─────────────────────────────────────────────────────────────

class VectorIndex {
  constructor(projectPath) {
    this.projectPath = projectPath;
    this.indexPath = path.join(projectPath, 'data', 'vectors');
    this.indexFile = path.join(this.indexPath, 'index.json');
    this.vectors = [];
    this.documents = [];
  }

  /**
   * 加载或创建索引
   */
  async load() {
    if (fs.existsSync(this.indexFile)) {
      const data = JSON.parse(fs.readFileSync(this.indexFile, 'utf-8'));
      this.vectors = data.vectors || [];
      this.documents = data.documents || [];

